const csvData = items[0].binary.data;
const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
const csvString = binaryData.toString('utf-8');
const lines = csvString.trim().split('\n');
const headers = lines[0].split(',').map(h => h.trim());
const result = [];
for (let i = 1; i < lines.length; i++) {
  const values = lines[i].split(',').map(v => v.trim());
  const row = {};
  headers.forEach((h, idx) => {
    let val = values[idx];
    if (val === '') val = null;
    if (['edad','anos_cliente','llamadas_mes','reclamos','plan_premium','abandona'].includes(h)) {
      val = parseInt(val, 10);
    } else if (['uso_datos_gb','prob_abandono'].includes(h)) {
      val = parseFloat(val);
    }
    row[h] = val;
  });
  result.push({ json: row });
}
return result;
